const body = $input.item.json.body || $input.item.json;

const campagne_id = body.campagne_id;
const attachments = body.attachments || [];
const reply_to = body.reply_to || '';
const from_name = body.from_name || 'RIUSC';
const from_email = body.from_email || 'noreply@aqbrs.ca';
const signature_html = body.signature_html || '';
const inbound_domain = body.inbound_domain || 'reply.aqbrs.ca';

// Cles API passees par le portail
const resend_api_key = body.resend_api_key;
const supabase_url = body.supabase_url;
const supabase_service_key = body.supabase_service_key;

if (!campagne_id) throw new Error('campagne_id manquant');
if (!resend_api_key) throw new Error('resend_api_key manquant');
if (!supabase_service_key) throw new Error('supabase_service_key manquant');

console.log('Campagne:', campagne_id, '- PJ:', attachments.length);

return {
  json: {
    campagne_id,
    attachments,
    reply_to,
    from_name,
    from_email,
    signature_html,
    inbound_domain,
    resend_api_key,
    supabase_url,
    supabase_service_key
  }
};

const params = $input.item.json;
const SUPA_KEY = params.supabase_service_key;
const SUPA_URL = params.supabase_url;
const headers = {
  'apikey': SUPA_KEY,
  'Authorization': 'Bearer ' + SUPA_KEY,
  'Content-Type': 'application/json'
};

// 1. Charger tous les courriels queued de cette campagne
const courriels = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPA_URL}/rest/v1/courriels?campagne_id=eq.${params.campagne_id}&statut=eq.queued&select=id,benevole_id,to_email,subject,body_html&order=created_at.asc`,
  headers
});

console.log('Courriels queued:', courriels.length);

if (!courriels || courriels.length === 0) {
  console.log('Aucun courriel queued pour cette campagne');
  return { json: { ...params, courriels: [], attachments_base64: [] } };
}

// 2. Telecharger les PJ depuis Supabase Storage (1 seule fois)
const attachments_base64 = [];
for (const att of params.attachments) {
  if (!att.storage_path) continue;
  try {
    console.log('Telechargement PJ:', att.filename, att.storage_path);
    // Creer une URL signee
    const signResult = await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPA_URL}/storage/v1/object/sign/certificats/${att.storage_path}`,
      headers,
      body: JSON.stringify({ expiresIn: 3600 })
    });

    if (signResult && signResult.signedURL) {
      const fullUrl = signResult.signedURL.startsWith('http') 
        ? signResult.signedURL 
        : `${SUPA_URL}/storage/v1${signResult.signedURL}`;

      // Telecharger le fichier
      const fileBuffer = await this.helpers.httpRequest({
        method: 'GET',
        url: fullUrl,
        encoding: 'arraybuffer',
        returnFullResponse: false,
        json: false
      });

      const base64 = Buffer.from(fileBuffer).toString('base64');
      attachments_base64.push({
        filename: att.filename,
        content: base64
      });
      console.log('PJ telechargee:', att.filename, '- taille:', Math.round(base64.length / 1024), 'KB');
    }
  } catch (e) {
    console.error('Erreur telechargement PJ:', att.filename, e.message);
  }
}

return {
  json: {
    ...params,
    courriels,
    attachments_base64
  }
};

const data = $input.item.json;
const SUPA_KEY = data.supabase_service_key;
const SUPA_URL = data.supabase_url;
const RESEND_KEY = data.resend_api_key;
const supaHeaders = {
  'apikey': SUPA_KEY,
  'Authorization': 'Bearer ' + SUPA_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const courriels = data.courriels || [];
if (courriels.length === 0) {
  console.log('Aucun courriel a envoyer');
  return { json: { campagne_id: data.campagne_id, envoyes: 0, echoues: 0 } };
}

// Preparer les PJ pour Resend (base64)
const resendAttachments = (data.attachments_base64 || []).map(a => ({
  filename: a.filename,
  content: a.content
}));

let envoyes = 0;
let echoues = 0;
const BATCH_SIZE = 10;

console.log(`Debut envoi: ${courriels.length} courriels, ${resendAttachments.length} PJ, lots de ${BATCH_SIZE}`);

for (let i = 0; i < courriels.length; i += BATCH_SIZE) {
  const batch = courriels.slice(i, i + BATCH_SIZE);

  const results = await Promise.allSettled(
    batch.map(async (courriel) => {
      const dynamicReplyTo = `reply+${courriel.id}@${data.inbound_domain}`;

      try {
        const response = await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://api.resend.com/emails',
          headers: {
            'Authorization': `Bearer ${RESEND_KEY}`,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            from: `${data.from_name} <${data.from_email}>`,
            to: [courriel.to_email],
            subject: courriel.subject,
            html: courriel.body_html,
            reply_to: dynamicReplyTo,
            headers: { 'X-Entity-Ref-ID': courriel.benevole_id },
            tags: [{ name: 'source', value: 'portail-riusc' }],
            ...(resendAttachments.length > 0 ? { attachments: resendAttachments } : {})
          })
        });

        const resendId = response?.id || null;

        await this.helpers.httpRequest({
          method: 'PATCH',
          url: `${SUPA_URL}/rest/v1/courriels?id=eq.${courriel.id}`,
          headers: supaHeaders,
          body: JSON.stringify({ statut: 'sent', resend_id: resendId })
        });

        return { ok: true };
      } catch (e) {
        console.error('Erreur envoi', courriel.to_email, ':', e.message);

        try {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: `${SUPA_URL}/rest/v1/courriels?id=eq.${courriel.id}`,
            headers: supaHeaders,
            body: JSON.stringify({ statut: 'failed' })
          });
        } catch (e2) {
          console.error('Erreur update failed:', e2.message);
        }

        return { ok: false, error: e.message };
      }
    })
  );

  for (const r of results) {
    if (r.status === 'fulfilled' && r.value.ok) envoyes++;
    else echoues++;
  }

  const done = Math.min(i + BATCH_SIZE, courriels.length);
  console.log(`Progression: ${done}/${courriels.length} (${envoyes} ok, ${echoues} erreurs)`);
}

// Mettre a jour le total de la campagne
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPA_URL}/rest/v1/courriel_campagnes?id=eq.${data.campagne_id}`,
    headers: supaHeaders,
    body: JSON.stringify({ total_envoyes: envoyes })
  });
  console.log(`Campagne ${data.campagne_id} terminee: ${envoyes} envoyes, ${echoues} echoues`);
} catch (e) {
  console.error('Erreur update campagne:', e.message);
}

return {
  json: {
    campagne_id: data.campagne_id,
    envoyes,
    echoues,
    total: courriels.length
  }
};
